output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?film WHERE {
  ?film wdt:P31 wd:Q11424 .
  {
    ?film wdt:P57 wd:Q43203
  } UNION {
    ?film wdt:P161 wd:Q43203
  }
  .
  ?film wdt:P166 ?award .
  ?award wdt:P279 * wd:Q23069 .
}
ORDER BY DESC(?awardCount)
LIMIT 1

args.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?film (COUNT(?award) AS ?totalAwards)
WHERE {
  ?film wdt:P31 wd:Q11424;
        wdt:P57 wd:Q43203.
  {
    ?film wdt:P166 ?award.
    ?award wdt:P279* wd:Q23069.
  }
  UNION
  {
    ?film wdt:P166 ?award.
    ?award wdt:P279* wd:Q595202.
  }
}
GROUP BY ?film
ORDER BY DESC(?totalAwards)
LIMIT 1

